import SwiftUI

/// An immutable style describing how to format and paint text.
///
/// `TextStyle` provides a comprehensive way to define text appearance including
/// font family, size, weight, color, spacing, and decorative elements. It's designed
/// to be thread-safe and immutable, making it suitable for use across different
/// concurrency contexts.
///
/// ### Example Usage
/// ```swift
/// let titleStyle = TextStyle(
///     color: .black,
///     fontFamily: .sanfrancisco,
///     fontSize: 24,
///     weight: .bold
/// )
/// ```
public struct TextStyle: Sendable {
    /// The color to use when painting the text.
    ///
    /// This property defines the foreground color of the text. It can be any
    /// color that conforms to the `Color` protocol.
    public let color: Color

    /// The decoration for the text (e.g., underline, strikethrough).
    ///
    /// This optional property adds visual decorations to the text. When `nil`,
    /// no decoration is applied.
    public let decoration: Decoration?

    /// The design variant of the text (e.g., italic).
    ///
    /// This optional property modifies the text design. When `nil`, the default
    /// design is used.
    public let design: TextStyle.Design?

    /// The font family to use when painting the text.
    ///
    /// This property specifies which font family to use (e.g., SF Pro Text,
    /// San Francisco). The actual font name is generated by combining this
    /// with the weight, width, and design properties.
    public let fontFamily: FontFamily

    /// The size of glyphs (in logical pixels) to use when painting the text.
    ///
    /// This property defines the font size in points. The actual rendered size
    /// may vary based on the device's display characteristics and accessibility settings.
    public let fontSize: CGFloat

    /// Sets the spacing, or kerning, between characters.
    ///
    /// This property controls the horizontal spacing between individual characters.
    /// Positive values increase spacing, negative values decrease spacing.
    public let kerning: CGFloat

    /// The amount of space between lines of text.
    ///
    /// This property controls the vertical spacing between lines of text.
    /// Positive values increase line spacing, negative values decrease it.
    public let lineSpacing: CGFloat

    /// The typeface thickness to use when painting the text (e.g., bold, light).
    ///
    /// This optional property specifies the font weight. When `nil`, the default
    /// weight for the font family is used.
    public let weight: TextStyle.Weight?

    /// The width variant of the text (e.g., condensed).
    ///
    /// This optional property specifies the font width. When `nil`, the default
    /// width for the font family is used.
    public let width: TextStyle.Width?

    // MARK: - Computed Properties

    /// The complete font name based on its family, weight, width, and design.
    ///
    /// This computed property generates the full font name by combining the font
    /// family with any specified weight, width, and design modifiers.
    ///
    /// ### Example
    /// ```swift
    /// let style = TextStyle(fontFamily: .sanfrancisco, weight: .bold)
    /// print(style.fontName) // "SF Pro Text Bold"
    /// ```
    public var fontName: String {
        var fontName = fontFamily.rawValue

        if let weight {
            fontName += "-\(weight.rawValue)"
        }

        if let width {
            fontName += "-\(width.rawValue)"
        }

        if let design {
            fontName += "-\(design.rawValue)"
        }

        return fontName
    }

    // MARK: - Public methods

    /// Returns a copy of this `TextStyle` with the given fields replaced with new values.
    ///
    /// This method creates a new `TextStyle` instance, replacing only the specified
    /// properties while keeping all other properties unchanged. This is useful for
    /// creating variations of existing text styles.
    ///
    /// - Parameters:
    ///   - color: The new color to use (optional)
    ///   - decoration: The new decoration to apply (optional)
    ///   - design: The new design variant to use (optional)
    ///   - fontFamily: The new font family to use (optional)
    ///   - fontSize: The new font size to use (optional)
    ///   - kerning: The new kerning value to use (optional)
    ///   - lineSpacing: The new line spacing value to use (optional)
    ///   - weight: The new font weight to use (optional)
    ///   - width: The new font width to use (optional)
    /// - Returns: A new `TextStyle` instance with the specified changes
    public func copyWith(
        color: Color? = nil,
        decoration: TextStyle.Decoration? = nil,
        design: TextStyle.Design? = nil,
        fontFamily: FontFamily? = nil,
        fontSize: CGFloat? = nil,
        kerning: CGFloat? = nil,
        lineSpacing: CGFloat? = nil,
        weight: TextStyle.Weight? = nil,
        width: TextStyle.Width? = nil
    ) -> TextStyle {
        TextStyle(
            color: color ?? self.color,
            decoration: decoration ?? self.decoration,
            design: design ?? self.design,
            fontFamily: fontFamily ?? self.fontFamily,
            fontSize: fontSize ?? self.fontSize,
            kerning: kerning ?? self.kerning,
            lineSpacing: lineSpacing ?? self.lineSpacing,
            weight: weight ?? self.weight,
            width: width ?? self.width
        )
    }
}

extension TextStyle {
    /// The design variant of the text.
    ///
    /// This struct represents different design variants that can be applied to text,
    /// such as italic. It provides type-safe access to text design options.
    public struct Design: Hashable, RawRepresentable, Sendable {
        /// The corresponding value of the raw type.
        public let rawValue: String

        // MARK: - Initializer

        /// Creates a new instance with the specified raw value.
        ///
        /// - Parameter rawValue: The raw value to use for the new instance.
        public init(rawValue: String) {
            self.rawValue = rawValue
        }
    }
}

extension TextStyle.Design {
    /// Italic design variant.
    ///
    /// This design variant applies italic styling to the text, typically
    /// used for emphasis or to distinguish certain text elements.
    public static let italic = TextStyle.Design(rawValue: "Italic")
}

extension TextStyle {
    /// The decoration applied to the text.
    ///
    /// This enum defines visual decorations that can be applied to text,
    /// such as underlines or strikethroughs.
    public enum Decoration: Hashable, Sendable {
        /// Adds a strikethrough decoration to the text.
        ///
        /// This decoration draws a horizontal line through the text,
        /// commonly used to indicate deleted or deprecated content.
        case strikethrough

        /// Adds an underline decoration to the text.
        ///
        /// This decoration draws a horizontal line below the text,
        /// commonly used for emphasis or to indicate links.
        case underline
    }
}

extension TextStyle {
    /// The width variant of the text.
    ///
    /// This struct represents different width variants that can be applied to text,
    /// such as condensed. It provides type-safe access to text width options.
    public struct Width: Hashable, RawRepresentable, Sendable {
        /// The corresponding value of the raw type.
        public let rawValue: String

        // MARK: - Initializer

        /// Creates a new instance with the specified raw value.
        ///
        /// - Parameter rawValue: The raw value to use for the new instance.
        public init(rawValue: String) {
            self.rawValue = rawValue
        }
    }
}

extension TextStyle.Width {
    /// Condensed width variant.
    ///
    /// This width variant creates a more compact version of the font,
    /// useful for fitting more text in limited space.
    public static let condensed = TextStyle.Width(rawValue: "Condensed")
}

extension TextStyle {
    /// The thickness or weight of the text.
    ///
    /// This struct represents different font weights that can be applied to text,
    /// from light to extra bold. It provides type-safe access to font weight options.
    public struct Weight: Hashable, RawRepresentable, Sendable {
        /// The corresponding value of the raw type.
        public let rawValue: String

        // MARK: - Initializer

        /// Creates a new instance with the specified raw value.
        ///
        /// - Parameter rawValue: The raw value to use for the new instance.
        public init(rawValue: String) {
            self.rawValue = rawValue
        }
    }
}

extension TextStyle.Weight {
    /// Bold weight (w700).
    ///
    /// This weight creates a bold version of the font, commonly used
    /// for headings and emphasis.
    public static let bold = TextStyle.Weight(rawValue: "Bold")

    /// Light weight (w300).
    ///
    /// This weight creates a light version of the font, commonly used
    /// for subtle text elements.
    public static let light = TextStyle.Weight(rawValue: "Light")

    /// Medium weight (w500).
    ///
    /// This weight creates a medium version of the font, providing
    /// a balance between regular and bold.
    public static let medium = TextStyle.Weight(rawValue: "Medium")

    /// Regular weight (w400).
    ///
    /// This is the default weight for most fonts, providing
    /// standard readability.
    public static let regular = TextStyle.Weight(rawValue: "Regular")

    /// Semibold weight (w600).
    ///
    /// This weight creates a semibold version of the font, stronger
    /// than medium but lighter than bold.
    public static let semiBold = TextStyle.Weight(rawValue: "SemiBold")

    /// Extra bold weight (w900).
    ///
    /// This weight creates the heaviest version of the font,
    /// providing maximum emphasis.
    public static let xBold = TextStyle.Weight(rawValue: "XBold")
}

extension TextStyle {
    /// A type-safe representation of font families used within the application.
    ///
    /// `FontFamily` provides a structured way to manage and use different font families,
    /// ensuring consistency and reducing the risk of typographical errors. It conforms to both
    /// `RawRepresentable` and `Sendable`, making it suitable for use across different concurrency contexts.
    ///
    /// ### Example Usage
    /// ```swift
    /// let customFont = FontFamily(rawValue: "HelveticaNeue")
    /// print("Using font: \(customFont.rawValue)")
    /// ```
    public struct FontFamily: RawRepresentable, Sendable {
        /// The corresponding value of the raw type.
        public let rawValue: String

        // MARK: - Static Properties

        /// A predefined font family representing San Francisco (SF Pro Text).
        ///
        /// This font family uses Apple's San Francisco font system, specifically
        /// SF Pro Text which is optimized for body text and general UI elements.
        /// It provides excellent readability and supports various weights and styles.
        ///
        /// ### Available Weights
        /// - Light (w300)
        /// - Regular (w400)
        /// - Medium (w500)
        /// - Semibold (w600)
        /// - Bold (w700)
        /// - Heavy (w900)
        ///
        /// ### Example Usage
        /// ```swift
        /// let titleStyle = TextStyle(
        ///     fontFamily: .sanfrancisco,
        ///     fontSize: 24,
        ///     weight: .bold
        /// )
        /// ```
        public static let sanfrancisco = FontFamily(rawValue: "SFProText")

        // MARK: - Initializer

        /// Creates a new instance with the specified raw value.
        ///
        /// - Parameter rawValue: The raw value to use for the new instance.
        public init(rawValue: String) {
            self.rawValue = rawValue
        }
    }
}
